export default {
  data: function data() {
    return {
      dialogVisible: false,
      loading: false,
      orderInfo: {
        id: '',
        startTime: '',
        amount: 0,
        deliveryAddress: '',
        deliveryPhone: '',
        remark: '',
        orderStatus: 0,
        user: {
          id: '',
          name: ''
        },
        send: {
          id: '',
          name: '',
          phone: ''
        },
        purchasesItems: []
      }
    };
  },
  methods: {
    // 格式化时间
    formatTime: function formatTime(time) {
      if (!time) return '-';
      var date = new Date(time);
      var year = date.getFullYear();
      var month = String(date.getMonth() + 1).padStart(2, '0');
      var day = String(date.getDate()).padStart(2, '0');
      var hours = String(date.getHours()).padStart(2, '0');
      var minutes = String(date.getMinutes()).padStart(2, '0');
      var seconds = String(date.getSeconds()).padStart(2, '0');
      return year + '-' + month + '-' + day + ' ' + hours + ':' + minutes + ':' + seconds;
    },
    // 加载订单详情
    loadOrderDetail: function loadOrderDetail(id) {
      var _this = this;

      this.loading = true;
      this.$http.get("/api/orderCtl/findOrderById?id=" + id).then(function (resp) {
        _this.loading = false;
        console.log('订单详情响应:', resp.data);

        if (resp.data && resp.data.data) {
          _this.orderInfo = resp.data.data; // 确保 purchasesItems 是数组

          if (!_this.orderInfo.purchasesItems) {
            _this.orderInfo.purchasesItems = [];
          }

          console.log('订单详情:', _this.orderInfo);
        } else {
          _this.$message({
            type: 'error',
            message: '获取订单详情失败',
            duration: 2000
          });
        }
      }).catch(function (error) {
        _this.loading = false;
        console.error('加载订单详情失败:', error);
        var errorMsg = '加载订单详情失败';

        if (error.response && error.response.data && error.response.data.msg) {
          errorMsg = error.response.data.msg;
        }

        _this.$message({
          type: 'error',
          message: errorMsg,
          duration: 2000
        });
      });
    }
  }
};
